ll n, k; // 数组长度，操作长度
var a = vector<ll>(n + 10, 0); // 初始数组
var D = vector<ll>(n + 10, 0); // 一阶差分数组

ll sum = 0; // 动态维护的一阶前缀和(代表当前位置的真实累计变化量)
fa(i, 1, n) {
    sum += D[i];   // 更新当前位置的累计变化量
    a[i] += sum;

    // 如果当前真实值不满足条件，需要发起一次区间加操作 [i, r]
    if (check(a[i])) { 
        // 假设需要加的值为 v

        ll l = i, r = min(n, i + k - 1); // 区间左右端点

      	// 正常下放一阶差分标记
        // D[l] += v;        // 理论上应该有这一步，但在动态维护中可省略
        D[r + 1] -= v;       // 在区间结束后的下一位减去影响

        // 因为 D[l] 的影响没有体现在当前的 sum 中，必须手动补上，
        // 这样下一次循环 i+1 时，sum 才能正确传递这个 v。
        sum += v; 

        // 更新原数组或统计答案
        a[i] += v; 
    }
}

ll n, k; // 数组长度，操作长度
var a = vector<ll>(n + 10, 0); 
var D = vector<ll>(n + 10, 0); // 二阶差分数组

ll sumd1 = 0; // 动态一阶前缀和 (等差数列的公差累积)
ll sumd2 = 0; // 动态二阶前缀和 (等差数列的实际数值累积)

fa(i, 1, n) {
    sumd1 += D[i];
    sumd2 += sumd1;
    a[i] += sumd2; // 得到被前面操作影响后的真实值

    if (check(a[i])) { // 需要在该位置新建等差数列覆盖
        ll l = i, r = min(n, i + k - 1);  // 区间左右端点

        // 根据题意计算操作次数或直接计算等差数列三要素：首项、公差、末项
        ll cnt = (a[i] + k - 1) / k; // 假设每次操作加 k, k-1...1，要加的次数为 cnt
        ll a1 = k * cnt; 
        ll d = -cnt;
        ll an = cnt; 

        a[i] += a1;

        // 正常下放二阶差分标记
        // D[l] += a1;
        D[l + 1] += d - a1;
        D[r + 1] += -d - an;
        D[r + 2] += an;

        // 当前正处于 l 处，必须立刻将首项 a1 的影响注入状态变量中！
        sumd1 += a1;
        sumd2 += a1;
    }
}
